import { cli, Strategy } from '@jackwener/opencli/registry';

cli({
  site: 'test-zhihu',
  name: 'hot',
  description: '知乎热榜 (cookie strategy)',
  domain: 'www.zhihu.com',
  strategy: Strategy.COOKIE,
  browser: true,
  args: [
    { name: 'limit', type: 'int', default: 10, help: 'Number of items' },
  ],
  columns: ['rank', 'title', 'heat'],
  func: async (page, kwargs) => {
    const limit = kwargs.limit ?? 10;
    await page.goto('https://www.zhihu.com');
    await page.wait(2);
    const result = await page.evaluate(`(async () => {
      const res = await fetch('https://www.zhihu.com/api/v3/feed/topstory/hot-lists/total?limit=50', {
        credentials: 'include'
      });
      const text = await res.text();
      const d = JSON.parse(text.replace(/("id"\s*:\s*)(\d{16,})/g, '$1"$2"'));
      return (d?.data || []).map((item) => {
        const t = item.target || {};
        return { title: t.title, heat: item.detail_text || '', answer_count: t.answer_count };
      });
    })()`);
    return (result as any[]).slice(0, limit).map((item, i) => ({
      rank: i + 1, title: item.title, heat: item.heat,
    }));
  },
});

import { cli, Strategy } from '@jackwener/opencli/registry';

cli({
  site: 'test-zhihu',
  name: 'search',
  description: '知乎搜索 (cookie strategy)',
  domain: 'www.zhihu.com',
  strategy: Strategy.COOKIE,
  browser: true,
  args: [
    { name: 'query', type: 'string', default: 'AI', positional: true, help: 'Search query' },
    { name: 'limit', type: 'int', default: 5, help: 'Number of results' },
  ],
  columns: ['rank', 'title', 'type', 'author', 'votes'],
  func: async (page, kwargs) => {
    const query = kwargs.query ?? 'AI';
    const limit = kwargs.limit ?? 5;
    await page.goto('https://www.zhihu.com');
    await page.wait(2);
    const result = await page.evaluate(`(async () => {
      const strip = (html) => (html || '').replace(/<[^>]+>/g, '').trim();
      const res = await fetch('https://www.zhihu.com/api/v4/search_v3?q=' + encodeURIComponent('${query}') + '&t=general&offset=0&limit=${limit}', {
        credentials: 'include'
      });
      const d = await res.json();
      return (d?.data || []).filter(item => item.type === 'search_result').map(item => {
        const obj = item.object || {};
        return { type: obj.type, title: strip(obj.title || ''), author: obj.author?.name || '', votes: obj.voteup_count || 0 };
      });
    })()`);
    return (result as any[]).slice(0, limit).map((item, i) => ({
      rank: i + 1, title: item.title, type: item.type, author: item.author, votes: item.votes,
    }));
  },
});

import { cli, Strategy } from '@jackwener/opencli/registry';

cli({
  site: 'test-zhihu',
  name: 'question',
  description: '知乎问题回答 (cookie strategy)',
  domain: 'www.zhihu.com',
  strategy: Strategy.COOKIE,
  browser: true,
  args: [
    { name: 'id', type: 'string', default: '19550225', positional: true, help: 'Question ID' },
    { name: 'limit', type: 'int', default: 5, help: 'Number of answers' },
  ],
  columns: ['rank', 'author', 'votes', 'excerpt'],
  func: async (page, kwargs) => {
    const qid = kwargs.id ?? '19550225';
    const limit = kwargs.limit ?? 5;
    await page.goto('https://www.zhihu.com/question/' + qid);
    await page.wait(2);
    const result = await page.evaluate(`(async () => {
      const strip = (html) => (html || '').replace(/<[^>]+>/g, '').trim();
      const res = await fetch('https://www.zhihu.com/api/v4/questions/${qid}/answers?limit=${limit}&offset=0&sort_by=default&include=data[*].content,voteup_count,comment_count,author', {
        credentials: 'include'
      });
      const d = await res.json();
      return (d?.data || []).map(a => ({
        author: a.author?.name || 'anonymous',
        votes: a.voteup_count || 0,
        excerpt: strip(a.content || '').slice(0, 100),
      }));
    })()`);
    return (result as any[]).slice(0, limit).map((a, i) => ({
      rank: i + 1, author: a.author, votes: a.votes, excerpt: a.excerpt,
    }));
  },
});

import { cli, Strategy } from '@jackwener/opencli/registry';

cli({
  site: 'test-xhs',
  name: 'feed',
  description: '小红书推荐 Feed (cookie strategy + DOM extraction)',
  domain: 'www.xiaohongshu.com',
  strategy: Strategy.COOKIE,
  browser: true,
  args: [
    { name: 'limit', type: 'int', default: 10, help: 'Number of items' },
  ],
  columns: ['rank', 'title', 'author', 'likes'],
  func: async (page, kwargs) => {
    const limit = kwargs.limit ?? 10;
    await page.goto('https://www.xiaohongshu.com/explore');
    await page.wait(3);
    const result = await page.evaluate(`(() => {
      const items = [];
      document.querySelectorAll('section.note-item, [data-v-a264b01a]').forEach(el => {
        const titleEl = el.querySelector('.title span, a.title');
        const authorEl = el.querySelector('.author-wrapper .name, .author .name');
        const likesEl = el.querySelector('.like-wrapper .count, .interact-container .count');
        if (titleEl) {
          items.push({
            title: titleEl.textContent?.trim() || '',
            author: authorEl?.textContent?.trim() || '',
            likes: likesEl?.textContent?.trim() || '0',
          });
        }
      });
      return items;
    })()`);
    return (result as any[]).slice(0, limit).map((item, i) => ({
      rank: i + 1, title: item.title, author: item.author, likes: item.likes,
    }));
  },
});

